q4.css:
.s-q4{container-type:inline-size;container-name:q4-root;display:flex;flex-direction:column;gap:16px;color:#FFFFFF;font-size:13px;line-height:1.5}
.s-q4 [class^="q4-"],.s-q4 [class*=" q4-"]{box-sizing:border-box}

/* 제목띠 */
.s-q4 .q4-band{display:flex;align-items:center;gap:10px;background:#39415a;border-radius:12px;padding:13px 18px}
.s-q4 .q4-band>svg{width:20px;height:20px;flex:none;color:#FFFFFF}
.s-q4 .q4-band-title{font-size:18px;font-weight:700;line-height:1.3}
.s-q4 .q4-band-sub{margin-left:auto;font-size:12px;font-weight:400;color:#AAB4C3;white-space:nowrap}

/* [사진+칩] 두 기둥 */
.s-q4 .q4-cols{display:grid;grid-template-columns:1fr 1fr;gap:16px;align-items:start}
.s-q4 .q4-col{display:flex;flex-direction:column;gap:10px;min-width:0}

/* 사진 밑 칩 패널 */
.s-q4 .q4-chippanel{background:#161B22;border:1px solid #293244;border-radius:12px;padding:12px 14px;box-shadow:0 2px 10px rgba(0,0,0,.22)}
.s-q4 .q4-chipcond{margin:0 0 10px;font-size:12px;font-weight:400;color:#7D8899;font-variant-numeric:tabular-nums;overflow-wrap:anywhere}
.s-q4 .q4-chips{display:flex;flex-wrap:wrap;gap:8px}
.s-q4 .q4-chip{display:inline-flex;align-items:baseline;gap:6px;padding:7px 12px;background:#131722;border:1px solid #293244;border-radius:999px;color:#FFFFFF;font-family:inherit;cursor:pointer;transition:border-color .15s ease}
.s-q4 .q4-chip:hover{border-color:#5491DA}
.s-q4 .q4-chip-k{font-size:12px;font-weight:400;color:#AAB4C3;white-space:nowrap}
.s-q4 .q4-chip-v{font-size:14px;font-weight:600;line-height:1.2;color:#FFFFFF;font-variant-numeric:tabular-nums;white-space:nowrap}
.s-q4 .q4-chip-u{font-size:11px;font-weight:500;color:#7D8899;white-space:nowrap}
.s-q4 .q4-chip-pen{align-self:center;width:12px;height:12px;flex:none;color:#5491DA;opacity:0;transition:opacity .15s ease}
.s-q4 .q4-chip:hover .q4-chip-pen,.s-q4 .q4-chip:focus-visible .q4-chip-pen{opacity:1}
.s-q4 .q4-chip-add{display:inline-flex;align-items:center;gap:5px;padding:7px 12px;background:none;border:1px dashed #293244;border-radius:999px;color:#7D8899;font-size:12px;font-weight:400;font-family:inherit;cursor:pointer;transition:border-color .15s ease,color .15s ease}
.s-q4 .q4-chip-add:hover{border-color:#5491DA;color:#5491DA}
.s-q4 .q4-chip-add>svg{width:14px;height:14px;flex:none}

/* 개별형 안내 한 줄 */
.s-q4 .q4-note{display:flex;align-items:flex-start;gap:7px;padding:0 2px;color:#7D8899;font-size:12px;font-weight:400}
.s-q4 .q4-note>svg{width:14px;height:14px;flex:none;margin-top:2px;color:#7D8899}

/* 코멘트 — 접힌 바 + 펼침 */
.s-q4 .q4-cmts{background:#161B22;border:1px solid #293244;border-radius:12px;overflow:hidden;box-shadow:0 2px 10px rgba(0,0,0,.22)}
.s-q4 .q4-cmt-bar{display:flex;align-items:center}
.s-q4 .q4-cmt-toggle{flex:1;min-width:0;display:flex;align-items:center;gap:10px;padding:13px 16px;background:none;border:0;color:#FFFFFF;font:inherit;text-align:left;cursor:pointer;transition:background .12s ease}
.s-q4 .q4-cmt-toggle:hover{background:#131722}
.s-q4 .q4-cmt-ic{width:18px;height:18px;flex:none;color:#AAB4C3}
.s-q4 .q4-cmt-title{font-size:14px;font-weight:600;white-space:nowrap}
.s-q4 .q4-cmt-badge{flex:none;font-size:11px;font-weight:500;color:#5491DA;background:#131722;border:1px solid #293244;border-radius:999px;padding:2px 9px;line-height:1.5}
.s-q4 .q4-cmt-preview{flex:1;min-width:0;font-size:12px;font-weight:400;color:#7D8899;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.s-q4 .q4-chev{margin-left:auto;flex:none;width:20px;height:20px;color:#7D8899;transition:transform .15s ease}
.s-q4 .q4-cmts.is-open .q4-chev{transform:rotate(180deg)}
.s-q4 .q4-cmt-add{flex:none;display:inline-flex;align-items:center;gap:6px;margin-right:12px;padding:7px 12px;border-radius:10px;border:1px solid #293244;background:#131722;color:#AAB4C3;font-size:12px;font-weight:400;font-family:inherit;cursor:pointer;white-space:nowrap;transition:border-color .15s ease,color .15s ease}
.s-q4 .q4-cmt-add:hover{border-color:#5491DA;color:#FFFFFF}
.s-q4 .q4-cmt-add>svg{width:14px;height:14px}
.s-q4 .q4-cmt-wrap{display:grid;grid-template-rows:0fr;transition:grid-template-rows .2s cubic-bezier(0.22,1,0.36,1)}
.s-q4 .q4-cmts.is-open .q4-cmt-wrap{grid-template-rows:1fr}
.s-q4 .q4-cmt-inner{overflow:hidden;min-height:0}
.s-q4 .q4-clist{border-top:1px solid #232C3A}
.s-q4 .q4-citem{display:flex;gap:11px;padding:13px 16px}
.s-q4 .q4-citem+.q4-citem{border-top:1px solid #232C3A}
.s-q4 .q4-cava{flex:none;width:26px;height:26px;border-radius:999px;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:500;color:#FFFFFF;margin-top:1px}
.s-q4 .q4-cbody{flex:1;min-width:0}
.s-q4 .q4-chead{display:flex;align-items:baseline;gap:8px;flex-wrap:wrap}
.s-q4 .q4-ctitle{font-size:14px;font-weight:600}
.s-q4 .q4-cauthor{font-size:12px;font-weight:400;color:#AAB4C3}
.s-q4 .q4-cdate{margin-left:auto;font-size:11px;font-weight:500;color:#7D8899;white-space:nowrap}
.s-q4 .q4-ctext{margin:3px 0 0;font-size:13px;font-weight:400;color:#AAB4C3}

.s-q4 .q4-chip:focus-visible,.s-q4 .q4-chip-add:focus-visible,.s-q4 .q4-cmt-toggle:focus-visible,.s-q4 .q4-cmt-add:focus-visible{outline:2px solid #5491DA;outline-offset:2px}

/* 390px 반응형 — [사진+칩] 기둥 세로 쌓임 */
@container q4-root (max-width:640px){
  .s-q4 .q4-cols{grid-template-columns:1fr}
  .s-q4 .q4-band-sub{display:none}
  .s-q4 .q4-cmt-preview{display:none}
  .s-q4 .q4-chip-pen{opacity:1}
}

q3.css:
.s-q3{container-type:inline-size;display:flex;flex-direction:column;gap:16px;color:#FFFFFF;font-size:13px;line-height:1.5;}
.s-q3 [class^="q3-"],.s-q3 [class*=" q3-"]{box-sizing:border-box;}

/* 제목띠 */
.s-q3 .q3-band{display:flex;align-items:center;gap:10px;background:#39415a;border-radius:12px;padding:12px 16px;box-shadow:0 2px 10px rgba(0,0,0,.22);}
.s-q3 .q3-band-ic{width:20px;height:20px;color:#FFFFFF;flex:none;}
.s-q3 .q3-band-t{margin:0;font-size:16px;font-weight:700;color:#FFFFFF;}
.s-q3 .q3-band-sub{margin-left:auto;font-size:11px;font-weight:500;color:#AAB4C3;}

/* 각 사 기준 표기 안내 — 한 줄 절제 */
.s-q3 .q3-notice{display:flex;align-items:flex-start;gap:7px;padding:0 2px;font-size:12px;font-weight:400;color:#7D8899;}
.s-q3 .q3-notice svg{width:14px;height:14px;flex:none;margin-top:2px;color:#7D8899;}

/* 제조사 기둥: 사진카드 + 바로 아래 칩 패널 (열 간격은 넓게, 기둥 내부는 좁게 = 소속감) */
.s-q3 .q3-lanes{display:grid;grid-template-columns:1fr 1fr;column-gap:20px;row-gap:16px;align-items:start;}
.s-q3 .q3-lane{display:flex;flex-direction:column;gap:10px;min-width:0;}

/* 칩 패널 — 사진 밑 메모판 */
.s-q3 .q3-chipdock{background:#161B22;border:1px solid #293244;border-radius:12px;box-shadow:0 2px 10px rgba(0,0,0,.22);padding:11px 14px 13px;display:flex;flex-direction:column;gap:9px;}
.s-q3 .q3-cline{margin:0;font-size:11px;font-weight:500;color:#7D8899;letter-spacing:.01em;overflow-wrap:anywhere;}
.s-q3 .q3-chiprow{display:flex;flex-wrap:wrap;gap:8px;}

/* 지표 칩 = 이름(흐림) + 값(강조) + 단위(흐림), 클릭 = 값 수정 */
.s-q3 .q3-chip{display:inline-flex;align-items:center;gap:6px;padding:7px 11px;background:#131722;border:1px solid #293244;border-radius:8px;color:#FFFFFF;font-family:inherit;line-height:1.2;cursor:pointer;transition:border-color .15s ease,background .15s ease;}
.s-q3 .q3-chip-k{font-size:12px;font-weight:400;color:#7D8899;}
.s-q3 .q3-chip-v{font-size:14px;font-weight:600;color:#FFFFFF;font-variant-numeric:tabular-nums;}
.s-q3 .q3-chip-u{font-size:11px;font-weight:500;color:#7D8899;}
.s-q3 .q3-chip-pen{width:12px;height:12px;flex:none;margin-left:-1px;color:#5491DA;opacity:0;transition:opacity .15s ease;}
.s-q3 .q3-chip:hover{border-color:#5491DA;background:#161B22;}
.s-q3 .q3-chip:hover .q3-chip-pen,.s-q3 .q3-chip:focus-visible .q3-chip-pen{opacity:1;}
.s-q3 .q3-chip:focus-visible{outline:2px solid #5491DA;outline-offset:2px;}

/* + 지표 추가 칩 — 점선, 흐림 → 호버 파랑 */
.s-q3 .q3-chip-add{display:inline-flex;align-items:center;gap:5px;padding:7px 11px;background:transparent;border:1px dashed #293244;border-radius:8px;color:#7D8899;font-size:12px;font-weight:500;font-family:inherit;line-height:1.2;cursor:pointer;transition:color .15s ease,border-color .15s ease;}
.s-q3 .q3-chip-add svg{width:13px;height:13px;flex:none;}
.s-q3 .q3-chip-add:hover{color:#5491DA;border-color:#5491DA;}
.s-q3 .q3-chip-add:focus-visible{outline:2px solid #5491DA;outline-offset:2px;}

/* 코멘트 — 상시 펼침, 판단의 본진 */
.s-q3 .q3-comments{background:#161B22;border:1px solid #293244;border-radius:12px;box-shadow:0 2px 10px rgba(0,0,0,.22);padding:16px;display:flex;flex-direction:column;gap:12px;}
.s-q3 .q3-chead{display:flex;align-items:center;gap:10px 12px;flex-wrap:wrap;}
.s-q3 .q3-ctitle{margin:0;display:flex;align-items:center;gap:8px;font-size:18px;font-weight:700;color:#FFFFFF;}
.s-q3 .q3-cico{width:18px;height:18px;color:#5491DA;flex:none;}
.s-q3 .q3-ccount{font-size:11px;font-weight:500;color:#AAB4C3;background:#131722;border:1px solid #293244;border-radius:999px;padding:3px 9px;}
.s-q3 .q3-chint{font-size:12px;font-weight:400;color:#7D8899;}
.s-q3 .q3-cadd{margin-left:auto;display:inline-flex;align-items:center;gap:6px;background:#5491DA;color:#FFFFFF;border:none;border-radius:10px;padding:8px 14px;font-size:14px;font-weight:600;cursor:pointer;transition:transform .15s cubic-bezier(0.22,1,0.36,1),box-shadow .15s ease;}
.s-q3 .q3-cadd svg{width:16px;height:16px;flex:none;}
.s-q3 .q3-cadd:hover{transform:translateY(-1px);box-shadow:0 8px 24px rgba(0,0,0,.3);}
.s-q3 .q3-cadd:focus-visible{outline:2px solid #FFFFFF;outline-offset:2px;}
.s-q3 .q3-clist{display:grid;grid-template-columns:1fr 1fr;gap:10px;}
.s-q3 .q3-cmt{background:#131722;border:1px solid #232C3A;border-radius:10px;padding:12px 14px;display:flex;flex-direction:column;gap:8px;min-width:0;}
.s-q3 .q3-cmt-top{display:flex;align-items:center;gap:9px;}
.s-q3 .q3-avatar{flex:none;width:24px;height:24px;border-radius:999px;display:inline-flex;align-items:center;justify-content:center;font-size:11px;font-weight:500;color:#FFFFFF;}
.s-q3 .q3-cmt-who{min-width:0;}
.s-q3 .q3-cmt-title{font-size:14px;font-weight:600;color:#FFFFFF;}
.s-q3 .q3-cmt-meta{margin-top:1px;font-size:11px;font-weight:500;color:#7D8899;}
.s-q3 .q3-cmt-body{margin:0;font-size:13px;font-weight:400;color:#AAB4C3;line-height:1.55;}

/* 좁은 컨테이너(≤640px): [사진+칩] 기둥 세로 스택, 칩 줄바꿈, 연필 상시 옅게 */
@container (max-width:640px){
  .s-q3 .q3-lanes{grid-template-columns:1fr;row-gap:20px;}
  .s-q3 .q3-clist{grid-template-columns:1fr;}
  .s-q3 .q3-chip-pen{opacity:.65;}
  .s-q3 .q3-band{flex-wrap:wrap;row-gap:2px;}
  .s-q3 .q3-band-sub{margin-left:30px;flex-basis:100%;}
  .s-q3 .q3-chint{order:3;flex-basis:100%;}
}

q1.css:
/* ===== 후보 1 : 지표 비교형 + 코멘트 상시 ===== */
.s-q1{container-type:inline-size;container-name:q1-root;display:flex;flex-direction:column;gap:14px;color:#FFFFFF;font-size:13px;line-height:1.5;word-break:keep-all;}
.s-q1 .q1-band svg,.s-q1 .q1-mx svg,.s-q1 .q1-cm svg{display:block;flex:none;}
.s-q1 button{font-family:inherit;}

/* 제목띠 */
.s-q1 .q1-band{background:#39415a;border-radius:12px;padding:14px 18px;display:flex;align-items:center;gap:12px;flex-wrap:wrap;box-shadow:0 2px 10px rgba(0,0,0,.22);}
.s-q1 .q1-band-ic{width:38px;height:38px;border-radius:10px;background:rgba(255,255,255,.10);display:flex;align-items:center;justify-content:center;color:#FFFFFF;flex:none;}
.s-q1 .q1-band-tt{font-size:18px;font-weight:700;line-height:1.25;}
.s-q1 .q1-band-sub{font-size:11px;font-weight:500;color:#AAB4C3;margin-top:2px;}
.s-q1 .q1-band-chips{margin-left:auto;display:flex;gap:6px;flex-wrap:wrap;}
.s-q1 .q1-bchip{font-size:11px;font-weight:500;color:#AAB4C3;background:rgba(255,255,255,.08);border:1px solid rgba(255,255,255,.14);border-radius:999px;padding:5px 10px;line-height:1;}

/* 사진 2열 */
.s-q1 .q1-photos{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px;}

/* 하단: 비교표(좌) + 코멘트(우) — 표 보면서 의견을 대조해 읽는 배치 */
.s-q1 .q1-main{display:grid;grid-template-columns:minmax(0,1.55fr) minmax(0,1fr);gap:14px;align-items:start;}
.s-q1 .q1-card{background:#161B22;border:1px solid #293244;border-radius:12px;box-shadow:0 2px 10px rgba(0,0,0,.22);}

/* 지표 비교 카드 */
.s-q1 .q1-mx-head{display:flex;align-items:center;gap:10px;flex-wrap:wrap;padding:16px 16px 0;}
.s-q1 .q1-mx-tt{margin:0;font-size:16px;font-weight:700;display:flex;align-items:center;gap:8px;}
.s-q1 .q1-mx-tt svg{color:#5491DA;}
.s-q1 .q1-verdict{display:inline-flex;align-items:center;gap:5px;font-size:11px;font-weight:500;color:#4DA167;background:rgba(77,161,103,.12);border:1px solid rgba(77,161,103,.35);border-radius:999px;padding:4px 10px;line-height:1;}
.s-q1 .q1-hint{margin-left:auto;font-size:11px;font-weight:500;color:#7D8899;}

/* 조건 상이 주의 (앰버, 과하지 않게) */
.s-q1 .q1-notice{margin:12px 16px 0;display:flex;gap:8px;align-items:flex-start;background:rgba(214,162,62,.09);border:1px solid rgba(214,162,62,.30);border-radius:10px;padding:9px 12px;}
.s-q1 .q1-notice svg{color:#D6A23E;margin-top:1px;}
.s-q1 .q1-notice p{margin:0;font-size:12px;line-height:1.5;}
.s-q1 .q1-notice-strong{color:#D6A23E;}
.s-q1 .q1-notice-rest{color:#AAB4C3;}

/* 비교표 */
.s-q1 .q1-table{margin:12px 16px 16px;border:1px solid #232C3A;border-radius:10px;overflow:hidden;background:#131722;}
.s-q1 .q1-tr{display:grid;grid-template-columns:132px minmax(0,1fr) minmax(0,1fr);}
.s-q1 .q1-tr + .q1-tr{border-top:1px solid #232C3A;}
.s-q1 .q1-tr > * + *{border-left:1px solid #232C3A;}
.s-q1 .q1-th,.s-q1 .q1-td{padding:12px 14px;min-width:0;}
.s-q1 .q1-thead{background:rgba(255,255,255,.02);}
.s-q1 .q1-th-metric{display:flex;align-items:flex-end;font-size:11px;font-weight:500;color:#7D8899;}
.s-q1 .q1-vh-name{font-size:14px;font-weight:600;}
.s-q1 .q1-vh-name span{font-size:12px;font-weight:400;color:#AAB4C3;}
.s-q1 .q1-vh-visit{display:flex;align-items:center;gap:6px;margin:6px 0 8px;}
.s-q1 .q1-vh-visit i{font-style:normal;font-size:11px;font-weight:500;color:#5491DA;background:rgba(84,145,218,.14);border-radius:999px;padding:3px 8px;line-height:1;}
.s-q1 .q1-vh-visit span{font-size:11px;font-weight:500;color:#7D8899;}
.s-q1 .q1-vh-cond{font-size:11px;font-weight:500;color:#AAB4C3;line-height:1.6;}
.s-q1 .q1-vh-cond span{color:#7D8899;margin-right:6px;}

.s-q1 .q1-row{transition:background .12s ease;}
.s-q1 .q1-row:hover{background:rgba(255,255,255,.02);}
.s-q1 .q1-mn{font-size:13px;}
.s-q1 .q1-md{display:flex;align-items:center;gap:4px;margin-top:3px;font-size:11px;font-weight:500;color:#7D8899;}
.s-q1 .q1-md svg{flex:none;}
.s-q1 .q1-val{position:relative;display:flex;align-items:center;gap:6px;}
.s-q1 .q1-num{font-size:16px;font-weight:700;letter-spacing:.01em;}
.s-q1 .q1-unit{font-size:11px;font-weight:500;color:#7D8899;}
.s-q1 .q1-win{background:rgba(77,161,103,.08);}
.s-q1 .q1-row:hover .q1-win{background:rgba(77,161,103,.11);}
.s-q1 .q1-wtag{display:inline-flex;align-items:center;gap:3px;font-size:11px;font-weight:500;color:#4DA167;background:rgba(77,161,103,.16);border-radius:999px;padding:3px 8px;line-height:1;white-space:nowrap;}
.s-q1 .q1-wtag svg{flex:none;}

/* 인라인 수정 진입점(호버 연필) */
.s-q1 .q1-edit{margin-left:auto;display:inline-flex;align-items:center;justify-content:center;width:26px;height:26px;border:0;border-radius:8px;background:transparent;color:#7D8899;cursor:pointer;opacity:0;transition:opacity .15s ease,background .15s ease,color .15s ease;}
.s-q1 .q1-edit svg{flex:none;}
.s-q1 .q1-row:hover .q1-edit,.s-q1 .q1-edit:focus-visible{opacity:1;}
.s-q1 .q1-edit:hover{color:#5491DA;background:rgba(84,145,218,.12);}
.s-q1 .q1-edit:focus-visible{outline:2px solid rgba(84,145,218,.6);outline-offset:1px;}

/* 종합 행 */
.s-q1 .q1-tr.q1-sum{background:rgba(255,255,255,.02);border-top:1px solid #293244;}
.s-q1 .q1-sum-l{display:flex;align-items:center;gap:7px;font-size:12px;color:#AAB4C3;}
.s-q1 .q1-sum-l svg{color:#D6A23E;flex:none;}
.s-q1 .q1-sum-v{display:flex;align-items:center;gap:6px;flex-wrap:wrap;}
.s-q1 .q1-sum-n{font-size:16px;font-weight:700;}
.s-q1 .q1-sum-d{font-size:11px;font-weight:500;color:#7D8899;}
.s-q1 .q1-sum-win{background:rgba(77,161,103,.10);}
.s-q1 .q1-sum-win .q1-sum-n{color:#4DA167;}

/* 코멘트 상시 보드 */
.s-q1 .q1-cm-head{display:flex;align-items:center;gap:8px;padding:16px 16px 12px;flex-wrap:wrap;}
.s-q1 .q1-cm-tt{margin:0;font-size:16px;font-weight:700;display:flex;align-items:center;gap:8px;}
.s-q1 .q1-cm-tt svg{color:#5491DA;}
.s-q1 .q1-cnt{font-size:11px;font-weight:500;color:#5491DA;background:rgba(84,145,218,.14);border-radius:999px;padding:3px 8px;line-height:1;}
.s-q1 .q1-add{margin-left:auto;display:inline-flex;align-items:center;gap:5px;font-size:12px;color:#FFFFFF;background:#5491DA;border:0;border-radius:10px;padding:8px 12px;line-height:1;cursor:pointer;transition:filter .15s ease,transform .12s ease;}
