.s-q1 .q1-add:active{transform:translateY(1px);}
.s-q1 .q1-add:focus-visible{outline:2px solid rgba(84,145,218,.6);outline-offset:2px;}
.s-q1 .q1-cm-list{display:flex;flex-direction:column;gap:10px;padding:0 16px 16px;}
.s-q1 .q1-cmt{background:#131722;border:1px solid #232C3A;border-radius:10px;padding:12px 14px;transition:border-color .15s ease;}
.s-q1 .q1-cmt:hover{border-color:#293244;}
.s-q1 .q1-cmt-h{display:flex;align-items:center;gap:8px;margin-bottom:7px;}
.s-q1 .q1-av{width:24px;height:24px;border-radius:999px;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:500;color:#FFFFFF;flex:none;}
.s-q1 .q1-av.q1-a1{background:#2f8f4e;}
.s-q1 .q1-av.q1-a2{background:#2f6db8;}
.s-q1 .q1-av.q1-a3{background:#a8761a;}
.s-q1 .q1-cmt-nm{font-size:12px;color:#AAB4C3;}
.s-q1 .q1-cmt-dt{margin-left:auto;font-size:11px;font-weight:500;color:#7D8899;}
.s-q1 .q1-cmt-tt{margin:0 0 4px;font-size:14px;font-weight:600;}
.s-q1 .q1-cmt-bd{margin:0;font-size:13px;color:#AAB4C3;line-height:1.55;}

/* 중간 폭: 표 풀폭 + 코멘트 2열 보드로 하강 */
@container q1-root (max-width:980px){
  .s-q1 .q1-main{grid-template-columns:1fr;}
  .s-q1 .q1-cm-list{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));}
}

/* 모바일 390px: 전부 세로 스택, 표는 3열 유지(축약), 연필 상시 노출 */
@container q1-root (max-width:640px){
  .s-q1 .q1-band{padding:12px 14px;}
  .s-q1 .q1-band-chips{display:none;}
  .s-q1 .q1-photos{grid-template-columns:1fr;}
  .s-q1 .q1-cm-list{grid-template-columns:1fr;}
  .s-q1 .q1-hint{display:none;}
  .s-q1 .q1-tr{grid-template-columns:96px minmax(0,1fr) minmax(0,1fr);}
