q2.css:
.s-q2{display:flex;flex-direction:column;gap:14px;color:#FFFFFF;}
.s-q2 *{box-sizing:border-box;}
.s-q2 button{font-family:inherit;}
.s-q2 button:focus-visible{outline:2px solid rgba(84,145,218,.6);outline-offset:2px;}

/* ---------- 제목띠 ---------- */
.s-q2 .q2-band{display:flex;align-items:center;gap:12px;background:#39415a;border-radius:12px;padding:12px 18px;box-shadow:0 2px 10px rgba(0,0,0,.22);}
.s-q2 .q2-band-ic{width:38px;height:38px;border-radius:10px;background:rgba(255,255,255,.10);display:flex;align-items:center;justify-content:center;color:#FFFFFF;flex:none;}
.s-q2 .q2-band-ic svg{width:22px;height:22px;}
.s-q2 .q2-band-t{min-width:0;}
.s-q2 .q2-band-cap{display:block;font-size:11px;font-weight:500;color:rgba(255,255,255,.62);letter-spacing:.02em;}
.s-q2 .q2-band-name{margin:1px 0 0;font-size:18px;font-weight:700;line-height:1.2;color:#FFFFFF;}
.s-q2 .q2-band-sub{margin-left:auto;font-size:12px;font-weight:400;color:rgba(255,255,255,.66);white-space:nowrap;}

/* ---------- 사진 2열 ---------- */
.s-q2 .q2-photos{display:grid;grid-template-columns:1fr 1fr;gap:14px;}

/* ---------- 지표 카드 ---------- */
.s-q2 .q2-metrics{background:#161B22;border:1px solid #293244;border-radius:12px;box-shadow:0 2px 10px rgba(0,0,0,.22);padding:16px 18px 8px;display:flex;flex-direction:column;gap:12px;}
.s-q2 .q2-mhead{display:flex;align-items:center;gap:10px;flex-wrap:wrap;}
.s-q2 .q2-mic{width:30px;height:30px;border-radius:8px;background:rgba(84,145,218,.14);color:#5491DA;display:flex;align-items:center;justify-content:center;flex:none;}
.s-q2 .q2-mic svg{width:18px;height:18px;}
.s-q2 .q2-mtitle{margin:0;font-size:16px;font-weight:700;color:#FFFFFF;}
.s-q2 .q2-verdict{margin-left:auto;display:flex;align-items:center;gap:6px;flex-wrap:wrap;}
.s-q2 .q2-vchip{display:inline-flex;align-items:center;gap:5px;padding:4px 10px;border-radius:999px;font-size:11px;font-weight:500;background:rgba(125,136,153,.14);color:#AAB4C3;border:1px solid rgba(125,136,153,.25);white-space:nowrap;}
.s-q2 .q2-vchip svg{width:13px;height:13px;}
.s-q2 .q2-vchip-win{background:rgba(77,161,103,.16);color:#4DA167;border-color:rgba(77,161,103,.35);}

/* 조건 상이 경고 */
.s-q2 .q2-warn{display:flex;align-items:flex-start;gap:8px;background:rgba(214,162,62,.09);border:1px solid rgba(214,162,62,.28);border-radius:10px;padding:9px 12px;}
.s-q2 .q2-warn svg{width:15px;height:15px;color:#D6A23E;flex:none;margin-top:2px;}
.s-q2 .q2-warn p{margin:0;font-size:12px;font-weight:400;line-height:1.5;color:#AAB4C3;}
.s-q2 .q2-warn-em{color:#D6A23E;}

/* 제조사별 조건 요약 */
.s-q2 .q2-cond{display:grid;grid-template-columns:1fr 1fr;gap:10px;}
.s-q2 .q2-cond-item{background:#131722;border:1px solid #232C3A;border-radius:10px;padding:10px 12px;display:flex;flex-direction:column;gap:8px;min-width:0;}
.s-q2 .q2-cond-top{display:flex;align-items:baseline;gap:6px;flex-wrap:wrap;}
.s-q2 .q2-cond-name{font-size:14px;font-weight:600;color:#FFFFFF;}
.s-q2 .q2-cond-model{font-size:12px;font-weight:400;color:#AAB4C3;}
.s-q2 .q2-cond-visit{margin-left:auto;font-size:11px;font-weight:500;color:#5491DA;background:rgba(84,145,218,.12);border-radius:999px;padding:2px 8px;white-space:nowrap;}
.s-q2 .q2-cond-chips{display:flex;flex-wrap:wrap;gap:6px;}
.s-q2 .q2-cond-chips span{font-size:11px;font-weight:500;color:#AAB4C3;background:#161B22;border:1px solid #293244;border-radius:8px;padding:3px 8px;white-space:nowrap;}

/* 비교표 */
.s-q2 .q2-table{--q2-cols:minmax(150px,1.25fr) minmax(90px,1fr) minmax(90px,1fr) minmax(110px,.9fr);}
.s-q2 .q2-thead,.s-q2 .q2-trow{display:grid;grid-template-columns:var(--q2-cols);gap:8px;align-items:center;}
.s-q2 .q2-thead{padding:2px 6px 8px;border-bottom:1px solid #232C3A;}
.s-q2 .q2-trow{padding:8px 6px;border-bottom:1px solid #232C3A;transition:background .15s ease;}
.s-q2 .q2-trow:last-child{border-bottom:0;}
.s-q2 .q2-trow:hover{background:rgba(84,145,218,.04);}
.s-q2 .q2-h-metric{font-size:11px;font-weight:500;color:#7D8899;}
.s-q2 .q2-h-v{display:flex;flex-direction:column;align-items:flex-end;font-size:14px;font-weight:600;color:#FFFFFF;line-height:1.25;padding-right:9px;}
.s-q2 .q2-h-v i{font-style:normal;font-size:11px;font-weight:500;color:#7D8899;}
.s-q2 .q2-h-j{font-size:11px;font-weight:500;color:#7D8899;text-align:center;}
.s-q2 .q2-c-metric b{display:block;font-size:14px;font-weight:600;color:#FFFFFF;line-height:1.3;}
.s-q2 .q2-dir{display:inline-flex;align-items:center;gap:3px;margin-top:2px;font-size:11px;font-weight:500;color:#7D8899;white-space:nowrap;}
.s-q2 .q2-dir svg{width:12px;height:12px;flex:none;}
.s-q2 .q2-vcell{position:relative;display:flex;align-items:center;justify-content:flex-end;gap:6px;padding:6px 8px;border-radius:8px;border:1px solid transparent;min-height:36px;}
.s-q2 .q2-val{font-size:16px;font-weight:700;color:#FFFFFF;font-variant-numeric:tabular-nums;line-height:1;}
.s-q2 .q2-win{background:rgba(77,161,103,.08);border-color:rgba(77,161,103,.22);}
.s-q2 .q2-win .q2-val{color:#4DA167;}
.s-q2 .q2-wic{width:15px;height:15px;color:#4DA167;flex:none;}
.s-q2 .q2-edit{position:absolute;left:5px;top:50%;transform:translateY(-50%);width:24px;height:24px;border:0;border-radius:8px;background:transparent;color:#7D8899;display:flex;align-items:center;justify-content:center;cursor:pointer;opacity:0;transition:opacity .12s ease,background .12s ease,color .12s ease;}
.s-q2 .q2-vcell:hover .q2-edit,.s-q2 .q2-edit:focus-visible{opacity:1;}
.s-q2 .q2-edit:hover{background:rgba(84,145,218,.14);color:#5491DA;}
.s-q2 .q2-edit svg{width:14px;height:14px;}
.s-q2 .q2-jcell{display:flex;flex-direction:column;align-items:center;gap:3px;}
.s-q2 .q2-jpill{font-size:11px;font-weight:500;color:#4DA167;background:rgba(77,161,103,.14);border:1px solid rgba(77,161,103,.3);border-radius:999px;padding:3px 10px;white-space:nowrap;}
.s-q2 .q2-jdiff{font-size:11px;font-weight:500;color:#7D8899;white-space:nowrap;}

/* ---------- 코멘트 접힘 바 ---------- */
.s-q2 .q2-cbar{background:#161B22;border:1px solid #293244;border-radius:12px;box-shadow:0 2px 10px rgba(0,0,0,.22);}
.s-q2 .q2-chead{display:flex;align-items:center;gap:8px;padding:6px 10px 6px 6px;flex-wrap:wrap;}
.s-q2 .q2-ctoggle{flex:1 1 auto;min-width:0;display:flex;align-items:center;gap:10px;padding:8px 10px;background:transparent;border:0;border-radius:10px;cursor:pointer;color:#FFFFFF;text-align:left;transition:background .15s ease;}
.s-q2 .q2-ctoggle:hover{background:rgba(84,145,218,.07);}
.s-q2 .q2-cico{width:30px;height:30px;border-radius:8px;background:rgba(84,145,218,.14);color:#5491DA;display:flex;align-items:center;justify-content:center;flex:none;}
.s-q2 .q2-cico svg{width:16px;height:16px;}
.s-q2 .q2-ctitle{font-size:16px;font-weight:700;white-space:nowrap;}
.s-q2 .q2-cbadge{font-size:11px;font-weight:500;color:#5491DA;background:rgba(84,145,218,.16);border-radius:999px;padding:2px 8px;flex:none;}
.s-q2 .q2-cprev{flex:1 1 auto;min-width:0;display:flex;align-items:center;gap:7px;overflow:hidden;transition:opacity .15s ease;}
.s-q2.q2-open .q2-cprev{opacity:0;pointer-events:none;}
.s-q2 .q2-cdot{width:7px;height:7px;border-radius:999px;flex:none;}
.s-q2 .q2-cprev-l{font-size:13px;font-weight:400;color:#FFFFFF;white-space:nowrap;flex:none;}
.s-q2 .q2-cprev-t{flex:1 1 auto;min-width:0;font-size:13px;font-weight:400;color:#7D8899;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}
.s-q2 .q2-cprev-d{font-size:11px;font-weight:500;color:#7D8899;flex:none;}
.s-q2 .q2-cchev{width:20px;height:20px;color:#7D8899;flex:none;transition:transform .2s cubic-bezier(0.22,1,0.36,1);}
.s-q2.q2-open .q2-cchev{transform:rotate(180deg);}
.s-q2 .q2-cadd{flex:none;display:inline-flex;align-items:center;gap:6px;padding:7px 12px;border-radius:10px;border:1px solid #293244;background:#131722;color:#AAB4C3;font-size:12px;font-weight:400;cursor:pointer;white-space:nowrap;transition:border-color .15s ease,color .15s ease,background .15s ease;}
.s-q2 .q2-cadd:hover{border-color:#5491DA;color:#5491DA;background:rgba(84,145,218,.08);}
.s-q2 .q2-cadd svg{width:14px;height:14px;}

/* 펼침 패널 */
.s-q2 .q2-cpanel{display:grid;grid-template-rows:0fr;transition:grid-template-rows .2s cubic-bezier(0.22,1,0.36,1);}
.s-q2 .q2-cpanel-in{overflow:hidden;min-height:0;opacity:0;transform:translateY(-4px);transition:opacity .2s ease,transform .2s cubic-bezier(0.22,1,0.36,1);padding:0 16px;}
.s-q2.q2-open .q2-cpanel{grid-template-rows:1fr;}
.s-q2.q2-open .q2-cpanel-in{opacity:1;transform:none;}
.s-q2 .q2-clist{border-top:1px solid #232C3A;}
.s-q2 .q2-citem{display:grid;grid-template-columns:28px minmax(0,1fr);gap:10px;padding:12px 0;}
.s-q2 .q2-citem+.q2-citem{border-top:1px solid #232C3A;}
.s-q2 .q2-cava{width:28px;height:28px;border-radius:999px;color:#FFFFFF;font-size:11px;font-weight:500;display:flex;align-items:center;justify-content:center;margin-top:2px;flex:none;}
.s-q2 .q2-crow1{display:flex;align-items:baseline;gap:8px;min-width:0;}
.s-q2 .q2-ctit{font-size:14px;font-weight:600;color:#FFFFFF;}
.s-q2 .q2-cname{font-size:12px;font-weight:400;}
.s-q2 .q2-cdate{margin-left:auto;font-size:11px;font-weight:500;color:#7D8899;flex:none;}
.s-q2 .q2-cbody{margin:3px 0 0;font-size:13px;font-weight:400;line-height:1.55;color:#AAB4C3;}
.s-q2 .q2-composer{display:flex;align-items:center;gap:8px;margin:2px 0 14px;background:#131722;border:1px solid #293244;border-radius:10px;padding:6px 6px 6px 12px;transition:border-color .15s ease;}
.s-q2 .q2-composer:focus-within{border-color:#5491DA;}
.s-q2 .q2-cinput{flex:1 1 auto;min-width:0;background:transparent;border:0;outline:0;color:#FFFFFF;font-size:13px;font-weight:400;font-family:inherit;}
.s-q2 .q2-cinput::placeholder{color:#7D8899;}
.s-q2 .q2-csubmit{flex:none;border:0;border-radius:8px;background:#5491DA;color:#FFFFFF;font-size:14px;font-weight:600;padding:6px 14px;cursor:pointer;transition:opacity .12s ease;}
.s-q2 .q2-csubmit:hover{opacity:.88;}

/* ---------- 모바일(컨테이너 640 이하) ---------- */
@container (max-width:640px){
  .s-q2 .q2-photos{grid-template-columns:1fr;}
  .s-q2 .q2-band-sub{display:none;}
  .s-q2 .q2-cond{grid-template-columns:1fr;}
  .s-q2 .q2-metrics{padding:14px 12px 4px;}
  .s-q2 .q2-table{--q2-cols:minmax(0,1.3fr) minmax(76px,1fr) minmax(76px,1fr);}
  .s-q2 .q2-h-j,.s-q2 .q2-jcell{display:none;}
  .s-q2 .q2-vcell{padding:6px 6px;}
  .s-q2 .q2-edit{opacity:.45;}
  .s-q2 .q2-ctoggle{flex-wrap:wrap;row-gap:6px;}
  .s-q2 .q2-cchev{margin-left:auto;}
  .s-q2 .q2-cprev{order:9;flex:1 1 100%;}
}

q2.js:
(function(){
  var root=document.querySelector('.s-q2');
  if(!root) return;
  var toggle=root.querySelector('.q2-ctoggle');
  var add=root.querySelector('.q2-cadd');
  var input=root.querySelector('.q2-cinput');
  var submit=root.querySelector('.q2-csubmit');
  function isOpen(){return root.classList.contains('q2-open');}
  function setOpen(v){
    root.classList.toggle('q2-open',v);
    if(toggle) toggle.setAttribute('aria-expanded',v?'true':'false');
  }
  if(toggle) toggle.addEventListener('click',function(){setOpen(!isOpen());});
  if(add) add.addEventListener('click',function(e){
    e.stopPropagation();
    setOpen(true);
    if(input) setTimeout(function(){input.focus();},210);
  });
  if(submit) submit.addEventListener('click',function(){
    if(input){input.value='';input.focus();}
  });
})()

