.s-q5 .q5-mv{font-size:16px;font-weight:700;color:#FFFFFF;font-variant-numeric:tabular-nums;line-height:1.2}
.s-q5 .q5-mu{font-size:11px;font-weight:500;color:#7D8899}
.s-q5 .q5-medit{margin-left:auto;align-self:center;display:inline-flex;align-items:center;justify-content:center;width:24px;height:24px;border:0;border-radius:8px;background:transparent;color:#5491DA;cursor:pointer;opacity:0;transition:opacity .15s ease,background .15s ease}
.s-q5 .q5-medit svg{width:13px;height:13px}
.s-q5 .q5-mitem:hover .q5-medit,.s-q5 .q5-medit:focus-visible{opacity:1}
.s-q5 .q5-medit:hover{background:rgba(84,145,218,.12)}
.s-q5 .q5-mcond{margin:3px 0 0;font-size:12px;font-weight:400;color:#7D8899;overflow-wrap:anywhere}
.s-q5 .q5-mmeta{display:flex;align-items:center;gap:5px;margin-top:5px;font-size:11px;font-weight:500;color:#7D8899}
.s-q5 .q5-mdot{width:6px;height:6px;border-radius:999px;flex:none}

/* "+ 지표" 점선 칩 — 이 열에 추가 = 이 제조사 지표 */
.s-q5 .q5-madd{margin-top:10px;align-self:flex-start;display:inline-flex;align-items:center;gap:5px;padding:6px 12px;background:transparent;border:1px dashed #293244;border-radius:8px;color:#7D8899;font-size:12px;font-weight:400;line-height:1.2;cursor:pointer;transition:color .15s ease,border-color .15s ease}
.s-q5 .q5-madd svg{width:13px;height:13px;flex:none}
.s-q5 .q5-madd:hover{color:#5491DA;border-color:#5491DA}

/* 메모 스트림 */
.s-q5 .q5-memos{border-top:1px solid #232C3A;padding:14px 18px 18px;display:flex;flex-direction:column;gap:12px}
.s-q5 .q5-msub{display:flex;align-items:center;gap:8px}
.s-q5 .q5-msub svg{width:15px;height:15px;flex:none;color:#AAB4C3}
.s-q5 .q5-msub b{font-size:14px;font-weight:600}
.s-q5 .q5-mcnt{font-size:11px;font-weight:500;color:#AAB4C3;background:#131722;border:1px solid #293244;border-radius:999px;padding:2px 8px;line-height:1.5}
.s-q5 .q5-mgrid{display:grid;grid-template-columns:1fr 1fr;gap:10px}
.s-q5 .q5-cmt{background:#131722;border:1px solid #232C3A;border-radius:10px;padding:12px 14px;display:flex;flex-direction:column;gap:8px;min-width:0}
.s-q5 .q5-cmt-top{display:flex;align-items:center;gap:9px}
.s-q5 .q5-avatar{flex:none;width:24px;height:24px;border-radius:999px;display:inline-flex;align-items:center;justify-content:center;font-size:11px;font-weight:500;color:#FFFFFF}
.s-q5 .q5-cmt-who{min-width:0}
.s-q5 .q5-cmt-title{font-size:14px;font-weight:600;color:#FFFFFF}
.s-q5 .q5-cmt-meta{margin-top:1px;font-size:11px;font-weight:500;color:#7D8899}
.s-q5 .q5-cmt-body{margin:0;font-size:13px;font-weight:400;color:#AAB4C3;line-height:1.55}
.s-q5 .q5-cadd{display:flex;align-items:center;justify-content:center;gap:6px;width:100%;padding:10px;background:transparent;border:1px dashed #293244;border-radius:10px;color:#7D8899;font-size:13px;font-weight:400;cursor:pointer;transition:color .15s ease,border-color .15s ease}
.s-q5 .q5-cadd svg{width:14px;height:14px;flex:none}
.s-q5 .q5-cadd:hover{color:#5491DA;border-color:#5491DA}

/* 세그먼트 선택에 따른 진입점 강조 (절제) */
.s-q5.q5-write-metric .q5-madd{border-color:rgba(84,145,218,.45);color:#5491DA}
.s-q5.q5-write-memo .q5-cadd{border-color:rgba(84,145,218,.45);color:#5491DA}

.s-q5 .q5-seg-btn:focus-visible,.s-q5 .q5-medit:focus-visible,.s-q5 .q5-madd:focus-visible,.s-q5 .q5-cadd:focus-visible{outline:2px solid #5491DA;outline-offset:2px}

/* 390px: 사진은 세로 스택, 지표는 좌=AMAT/우=Lam 2열 유지, 메모 1열 */
@container q5-root (max-width:640px){
  .s-q5 .q5-photos{grid-template-columns:1fr}
  .s-q5 .q5-band-sub{display:none}
  .s-q5 .q5-bhead{padding:12px 14px;row-gap:8px}
  .s-q5 .q5-mwrap{padding:12px 14px 14px}
  .s-q5 .q5-memos{padding:12px 14px 16px}
  .s-q5 .q5-mgrid{grid-template-columns:1fr}
  .s-q5 .q5-medit{opacity:.65}
  .s-q5 .q5-mcol-head{flex-wrap:wrap;row-gap:2px}
  .s-q5 .q5-mcond{font-size:11px;font-weight:500}
}

