(function(){
  var root=document.querySelector('.s-q5');
  if(!root) return;
  var btns=root.querySelectorAll('.q5-seg-btn');
  Array.prototype.forEach.call(btns,function(btn){
    btn.addEventListener('click',function(){
      Array.prototype.forEach.call(btns,function(b){
        var on=(b===btn);
        b.classList.toggle('on',on);
        b.setAttribute('aria-pressed',on?'true':'false');
      });
      var metric=btn.classList.contains('q5-seg-metric');
      root.classList.toggle('q5-write-metric',metric);
      root.classList.toggle('q5-write-memo',!metric);
    });
  });
})()
